import {
  forwardRef,
  useRef,
  cloneElement,
  isValidElement,
  type ReactElement,
} from 'react';
import { useTooltip, type TooltipConfig } from '../../hooks/useTooltip';
import type { TooltipPlacement } from '@o9ds/core';

export interface O9TooltipProps {
  /** Text content displayed in the tooltip */
  content: string;
  /** Preferred placement relative to the trigger element */
  placement?: TooltipPlacement;
  /** Keyboard shortcut hint displayed alongside the content */
  shortcut?: string;
  /** Single interactive child element that serves as the tooltip trigger */
  children: ReactElement;
}

/**
 * Standalone tooltip wrapper component. Wraps a single interactive child
 * and attaches tooltip behavior (hover/focus display, ARIA, positioning).
 *
 * ```tsx
 * <O9Tooltip content="Save document" shortcut="Ctrl+S">
 *   <button>Save</button>
 * </O9Tooltip>
 * ```
 */
export const O9Tooltip = forwardRef<HTMLElement, O9TooltipProps>(
  function O9Tooltip({ content, placement, shortcut, children }, forwardedRef) {
    const internalRef = useRef<HTMLElement | null>(null);

    const config: TooltipConfig = { content, placement, shortcut };

    useTooltip({
      triggerRef: internalRef,
      tooltip: config,
    });

    if (!isValidElement(children)) return children;

    return cloneElement(children as ReactElement<Record<string, unknown>>, {
      ref: (node: HTMLElement | null) => {
        internalRef.current = node;
        if (typeof forwardedRef === 'function') {
          forwardedRef(node);
        } else if (forwardedRef) {
          forwardedRef.current = node;
        }
        // Preserve original ref
        const originalRef = (children as ReactElement<Record<string, unknown>> & { ref?: unknown }).ref;
        if (typeof originalRef === 'function') {
          originalRef(node);
        } else if (originalRef && typeof originalRef === 'object' && 'current' in originalRef) {
          (originalRef as { current: HTMLElement | null }).current = node;
        }
      },
    });
  },
);
